import{_ as a,c,a1 as e,o}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Xem, Bật và Xóa Chính sách Kiểm toán sử dụng Auditpol","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/11-Auditpol.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/11-Auditpol.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/11-Auditpol.md"};function n(h,t,d,s,r,u){return o(),c("div",null,t[0]||(t[0]=[e('<h1 id="xem-bat-va-xoa-chinh-sach-kiem-toan-su-dung-auditpol" tabindex="-1">Xem, Bật và Xóa Chính sách Kiểm toán sử dụng Auditpol <a class="header-anchor" href="#xem-bat-va-xoa-chinh-sach-kiem-toan-su-dung-auditpol" aria-label="Permalink to &quot;Xem, Bật và Xóa Chính sách Kiểm toán sử dụng Auditpol&quot;">​</a></h1><p>Auditpol là một lệnh trong Windows Server 2016, 2012 và 2008, được yêu cầu để truy vấn hoặc cấu hình chính sách kiểm toán ở cấp danh mục con.</p><p>Auditpol hiển thị thông tin về hiệu suất và các hàm để điều khiển chính sách kiểm toán.</p><p><strong>Tài liệu Microsoft</strong>: <a href="https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/auditpol" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/auditpol</a></p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Cách thiết lập Chính sách Kiểm toán</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows Server 2016/2012.</li></ul><hr><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/aa898df1242308b3886dbf6d8c252a5dcb30089d/auditpol-syntax.png" alt="syntax"></p><table tabindex="0"><thead><tr><th>Lệnh</th><th>Mô tả</th></tr></thead><tbody><tr><td><code>/set</code></td><td>Đặt chính sách kiểm toán.</td></tr><tr><td><code>/get</code></td><td>Hiển thị chính sách kiểm toán hiện tại.</td></tr><tr><td><code>/backup</code></td><td>Lưu chính sách kiểm toán vào file.</td></tr><tr><td><code>/list</code></td><td>Hiển thị các phần tử chính sách có thể chọn.</td></tr><tr><td><code>/restore</code></td><td>Khôi phục chính sách kiểm toán từ file trước đó được tạo bằng auditpol/backup.</td></tr><tr><td><code>/remove</code></td><td>Xóa tất cả cài đặt chính sách kiểm toán theo người dùng và vô hiệu hóa tất cả cài đặt chính sách kiểm toán hệ thống.</td></tr><tr><td><code>/clear</code></td><td>Xóa chính sách kiểm toán.</td></tr><tr><td><code>/resourceSACL</code></td><td>Cấu hình danh sách kiểm soát truy cập hệ thống tài nguyên toàn cầu (SALCs).</td></tr></tbody></table><h3 id="đe-xem-tat-ca-chinh-sach-kiem-toan" tabindex="-1">Để xem tất cả chính sách kiểm toán: <a class="header-anchor" href="#đe-xem-tat-ca-chinh-sach-kiem-toan" aria-label="Permalink to &quot;Để xem tất cả chính sách kiểm toán:&quot;">​</a></h3><p>Khởi chạy <strong>Command Prompt</strong> từ Windows Server và nhập: <code>auditpol /get /category:*</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/aa898df1242308b3886dbf6d8c252a5dcb30089d/auditpol-1.png" alt="auditpol-category"></p><p>Để <strong>bật</strong> chính sách kiểm toán, nhập: <code>auditpol /set /category:&quot;system&quot;, &quot;account logon&quot; /success:enable /failure:enable</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fdf96591f9b797cf067e6118b0cc35caf00f6eb7/auditpol-2.png" alt="auditpol-enable"></p><p>Để kiểm tra chính sách kiểm toán đã được bật chưa, nhập: <code>auditpol /get /category:*</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8fe2d30ad3c2300f259ad9d4a56ccba2ded7d838/auditpol-3.png" alt="auditpol-success-failure"></p><p>Để <strong>xóa</strong> chính sách kiểm toán, nhập: <code>auditpol /clear /y</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/75ff457ae9710b831a2e867d9acf5e0947bd3958/auditpol-4.png" alt="auditclear"></p><p>Để kiểm tra chính sách kiểm toán đã được xóa chưa, nhập: <code>auditpol /get /category:*</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/39e8b217d60a368deaa7d384a43722747e643744/auditpol-5.png" alt="audit-check-clear"></p>',22)]))}const m=a(i,[["render",n]]);export{p as __pageData,m as default};
